import React, { useState, useEffect, useContext } from 'react';
import { Container, Typography, Button, Paper, List, ListItem, ListItemText, Dialog, DialogTitle, DialogContent, TextField, DialogActions, Box, Chip } from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import QrCodeIcon from '@mui/icons-material/QrCode';
import { useNavigate } from 'react-router-dom';
import api from '../services/api';
import { AuthContext } from '../context/AuthContext';

const Dashboard = () => {
    const [tags, setTags] = useState([]);
    const [openModal, setOpenModal] = useState(false);
    const [newItemName, setNewItemName] = useState('');
    const { logout } = useContext(AuthContext);
    const navigate = useNavigate();

    useEffect(() => {
        fetchTags();
    }, []);

    const fetchTags = async () => {
        try {
            const res = await api.get('/tags');
            setTags(res.data);
        } catch (err) {
            console.error(err);
        }
    };

    const handleCreateTag = async () => {
        if (!newItemName) return;
        try {
            await api.post('/tags', { itemName: newItemName });
            setOpenModal(false);
            setNewItemName('');
            fetchTags();
        } catch (err) {
            console.error(err);
        }
    };

    return (
        <Container maxWidth="md" sx={{ mt: 5 }}>
            <Box display="flex" justifyContent="space-between" alignItems="center" mb={4}>
                <Typography variant="h4" fontWeight="bold">My Tags</Typography>
                <Box>
                    <Button variant="contained" color="primary" startIcon={<AddIcon />} onClick={() => setOpenModal(true)} sx={{ mr: 2, borderRadius: 2 }}>
                        New Tag
                    </Button>
                    <Button variant="outlined" color="secondary" onClick={() => { logout(); navigate('/login'); }}>
                        Logout
                    </Button>
                </Box>
            </Box>

            <Paper elevation={3} sx={{ borderRadius: 3, overflow: 'hidden' }}>
                <List sx={{ width: '100%', bgcolor: 'background.paper' }}>
                    {tags.length === 0 ? (
                        <ListItem>
                            <ListItemText primary="No tags yet. Create one to protect your items!" />
                        </ListItem>
                    ) : (
                        tags.map((tag, idx) => (
                            <ListItem 
                                button 
                                key={tag.uuid} 
                                divider={idx !== tags.length -1}
                                onClick={() => navigate(`/tag/${tag.uuid}`)}
                            >
                                <QrCodeIcon sx={{ mr: 2, color: 'text.secondary' }} />
                                <ListItemText 
                                    primary={tag.itemName} 
                                    secondary={`ID: ${tag.uuid}`} 
                                    primaryTypographyProps={{ fontWeight: 'bold' }}
                                />
                                <Chip label={tag.active ? 'Active' : 'Inactive'} color={tag.active ? 'success' : 'default'} size="small" />
                            </ListItem>
                        ))
                    )}
                </List>
            </Paper>

            <Dialog open={openModal} onClose={() => setOpenModal(false)}>
                <DialogTitle>Create New Tag</DialogTitle>
                <DialogContent>
                    <TextField
                        autoFocus
                        margin="dense"
                        label="Item Name (e.g., House Keys, Laptop)"
                        fullWidth
                        variant="outlined"
                        value={newItemName}
                        onChange={(e) => setNewItemName(e.target.value)}
                    />
                </DialogContent>
                <DialogActions sx={{ px: 3, pb: 2 }}>
                    <Button onClick={() => setOpenModal(false)} color="inherit">Cancel</Button>
                    <Button onClick={handleCreateTag} variant="contained" color="primary">Create</Button>
                </DialogActions>
            </Dialog>
        </Container>
    );
};

export default Dashboard;

import React, { useState, useContext } from 'react';
import { Container, TextField, Button, Typography, Box, Paper, Alert } from '@mui/material';
import { useNavigate, Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import api from '../services/api';

const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const { login } = useContext(AuthContext);
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');
        try {
            const res = await api.post('/auth/login', { email, password });
            login(res.data.token);
            navigate('/dashboard');
        } catch (err) {
            setError('Invalid email or password.');
        }
    };

    return (
        <Container maxWidth="xs" sx={{ mt: 10 }}>
            <Paper elevation={4} sx={{ p: 4, borderRadius: 3, textAlign: 'center' }}>
                <Typography variant="h4" fontWeight="bold" gutterBottom color="primary">Welcome Back</Typography>
                <Typography variant="body2" color="textSecondary" mb={3}>Login to manage your anonymous QR tags</Typography>

                {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

                <form onSubmit={handleSubmit}>
                    <TextField 
                        fullWidth label="Email Address" variant="outlined" margin="normal"
                        value={email} onChange={(e) => setEmail(e.target.value)} required 
                    />
                    <TextField 
                        fullWidth label="Password" type="password" variant="outlined" margin="normal"
                        value={password} onChange={(e) => setPassword(e.target.value)} required 
                    />
                    <Button fullWidth type="submit" variant="contained" color="primary" size="large" sx={{ mt: 3, mb: 2, borderRadius: 2 }}>
                        Login
                    </Button>
                </form>
                <Typography variant="body2">
                    Don't have an account? <Link to="/register" style={{textDecoration: 'none', color: '#1976d2'}}>Sign up</Link>
                </Typography>
            </Paper>
        </Container>
    );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { Container, Typography, Paper, Box, Button, TextField, CircularProgress, Alert } from '@mui/material';
import { useParams } from 'react-router-dom';
import LocationOnIcon from '@mui/icons-material/LocationOn';
import CheckCircleOutlineIcon from '@mui/icons-material/CheckCircleOutline';
import api from '../services/api';

const ScanPage = () => {
    const { uuid } = useParams();
    const [location, setLocation] = useState(null);
    const [locError, setLocError] = useState('');
    const [message, setMessage] = useState('');
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState(false);

    useEffect(() => {
        // Request location immediately upon scanning
        if (navigator.geolocation) {
            navigator.geolocation.getCurrentPosition(
                (position) => {
                    setLocation({
                        lat: position.coords.latitude,
                        lng: position.coords.longitude
                    });
                },
                (error) => {
                    setLocError("Location access denied or unavailable. We cannot notify the owner precisely.");
                }
            );
        } else {
            setLocError("Geolocation is not supported by this browser.");
        }
    }, []);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await api.post(`/scan/${uuid}`, {
                message: message,
                lat: location ? location.lat : 0,
                lng: location ? location.lng : 0,
            });
            setSuccess(true);
        } catch (err) {
            console.error("Failed to submit scan", err);
            alert("Failed to notify owner. Invalid Tag ID?");
        } finally {
            setLoading(false);
        }
    };

    if (success) {
        return (
            <Container maxWidth="sm" sx={{ mt: 10, textAlign: 'center' }}>
                <CheckCircleOutlineIcon color="success" sx={{ fontSize: 80, mb: 2 }} />
                <Typography variant="h4" fontWeight="bold" gutterBottom>Thank You!</Typography>
                <Typography variant="body1" color="textSecondary">
                    The owner has been anonymously notified about the location of this item.
                </Typography>
            </Container>
        );
    }

    return (
        <Container maxWidth="sm" sx={{ mt: 8 }}>
            <Paper elevation={4} sx={{ p: 4, borderRadius: 3, textAlign: 'center' }}>
                <Typography variant="h4" fontWeight="bold" color="primary" gutterBottom>
                    Item Found
                </Typography>
                <Typography variant="body2" color="textSecondary" mb={4}>
                    You have found a lost item. Help reunite it with its owner by submitting the form below. 
                    Your identity remains completely anonymous.
                </Typography>

                {!location && !locError && (
                    <Box display="flex" justifyContent="center" alignItems="center" mb={3}>
                        <CircularProgress size={24} sx={{ mr: 2 }} />
                        <Typography variant="body2">Acquiring location...</Typography>
                    </Box>
                )}

                {location && (
                    <Alert severity="success" icon={<LocationOnIcon />} sx={{ mb: 3, textAlign: 'left' }}>
                        Location acquired successfully.
                    </Alert>
                )}

                {locError && (
                    <Alert severity="warning" sx={{ mb: 3, textAlign: 'left' }}>
                        {locError}
                    </Alert>
                )}

                <form onSubmit={handleSubmit}>
                    <TextField
                        fullWidth
                        label="Leave a message (Optional)"
                        multiline
                        rows={3}
                        variant="outlined"
                        placeholder="e.g. I left it at the front desk of the library."
                        value={message}
                        onChange={(e) => setMessage(e.target.value)}
                        sx={{ mb: 3 }}
                    />

                    <Button 
                        fullWidth 
                        type="submit" 
                        variant="contained" 
                        color="primary" 
                        size="large" 
                        disabled={loading}
                        sx={{ borderRadius: 2, height: 50 }}
                    >
                        {loading ? <CircularProgress size={24} color="inherit" /> : 'Notify Owner'}
                    </Button>
                </form>
            </Paper>
        </Container>
    );
};

export default ScanPage;

import React, { useState, useEffect } from 'react';
import { Container, Typography, Paper, Box, Button, List, ListItem, ListItemText, Divider, IconButton } from '@mui/material';
import { useParams, useNavigate } from 'react-router-dom';
import ArrowBackIcon from '@mui/icons-material/ArrowBack';
import MapIcon from '@mui/icons-material/Map';
import api from '../services/api';

const TagDetails = () => {
    const { uuid } = useParams();
    const navigate = useNavigate();
    const [history, setHistory] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchHistory();
    }, [uuid]);

    const fetchHistory = async () => {
        try {
            const res = await api.get(`/scan/history/${uuid}`);
            setHistory(res.data);
        } catch (err) {
            console.error("Error fetching history:", err);
        } finally {
            setLoading(false);
        }
    };

    const openMap = (lat, lng) => {
        window.open(`https://www.google.com/maps/search/?api=1&query=${lat},${lng}`, '_blank');
    };

    return (
        <Container maxWidth="md" sx={{ mt: 5 }}>
            <Box display="flex" alignItems="center" mb={3}>
                <IconButton onClick={() => navigate('/dashboard')} sx={{ mr: 2 }}>
                    <ArrowBackIcon />
                </IconButton>
                <Typography variant="h4" fontWeight="bold">Tag Details</Typography>
            </Box>

            <Paper elevation={3} sx={{ p: 4, borderRadius: 3, mb: 4, bgcolor: '#f5f5f5' }}>
                <Typography variant="subtitle1" color="textSecondary">Tag ID</Typography>
                <Typography variant="h6" fontWeight="bold" sx={{ wordBreak: 'break-all' }}>{uuid}</Typography>

                <Box mt={3} p={2} bgcolor="white" borderRadius={2} border="1px solid #e0e0e0" textAlign="center">
                    <Typography variant="body2" color="textSecondary" mb={1}>QR Code URL</Typography>
                    <Typography variant="body1" fontWeight="medium" color="primary">
                        {window.location.origin}/scan/{uuid}
                    </Typography>
                    <Typography variant="caption" display="block" mt={1}>
                        (You can generate a QR code pointing to this URL and attach it to your item)
                    </Typography>
                </Box>
            </Paper>

            <Typography variant="h5" fontWeight="bold" mb={2}>Scan History</Typography>
            <Paper elevation={3} sx={{ borderRadius: 3, overflow: 'hidden' }}>
                <List disablePadding>
                    {loading ? (
                        <ListItem><ListItemText primary="Loading history..." /></ListItem>
                    ) : history.length === 0 ? (
                        <ListItem><ListItemText primary="This tag has not been scanned yet." /></ListItem>
                    ) : (
                        history.map((scan, idx) => (
                            <React.Fragment key={scan.id}>
                                <ListItem alignItems="flex-start" sx={{ py: 2 }}>
                                    <ListItemText
                                        primary={
                                            <Typography variant="subtitle1" fontWeight="bold">
                                                Message: "{scan.message || 'No message provided'}"
                                            </Typography>
                                        }
                                        secondary={
                                            <React.Fragment>
                                                <Typography component="span" variant="body2" color="text.primary">
                                                    Date: {new Date(scan.timestamp).toLocaleString()}
                                                </Typography>
                                                <br />
                                                Location: {scan.latitude.toFixed(4)}, {scan.longitude.toFixed(4)}
                                            </React.Fragment>
                                        }
                                    />
                                    <Button 
                                        variant="outlined" 
                                        startIcon={<MapIcon />} 
                                        size="small"
                                        onClick={() => openMap(scan.latitude, scan.longitude)}
                                    >
                                        View Map
                                    </Button>
                                </ListItem>
                                {idx < history.length - 1 && <Divider component="li" />}
                            </React.Fragment>
                        ))
                    )}
                </List>
            </Paper>
        </Container>
    );
};

export default TagDetails;
